arguments.argument:
if global.gamePaused=false
{
  if deathFlail=1
  {
    hspeed=xVel
    vspeed=yVel
  }
  else
  {
    x=oMenaceMain.x-62
    y=oMenaceMain.y-54
    image_angle=bendAngle
    
    if laserWarn>0
    {
      laserWarn+=1
      circleAlpha-=0.06
      cirRad-=1
      if laserWarn>=15
      {
        laserWarn=0
        cirRad=32
        circleAlpha=1
      }
    }
  }
  enemyStepEvent()
}
else
{
  hspeed=0
  vspeed=0
}
